VALUES
  ('social-worker-moex-07330', 'social-worker', 'social-worker-moex-101-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在各種非理性的決策模式中，有一種模式是管理者將決策過程倒轉，對某些問題有既定的解決方案。管 理者一方面創造問題，一方面為自己創造決策的機會。這種模式稱之為：', '["漸進決策模式", "滿意決策模式", "有限理性決策模式", "垃圾桶決策模式"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "4f33f4a30a29", "answer_pdf_sha1": "3fcd0bbbc8ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07331', 'social-worker', 'social-worker-moex-101-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '實務工作者就是品質的管理者，需檢驗整個照顧計畫是否按照設計的計畫來執行，照顧管理者設計一套 回饋系統，測量計畫成功與否，這樣的努力主要是展現下列那一個管理概念？', '["品管圈", "全面品質管理", "服務協議", "績效考核"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "4f33f4a30a29", "answer_pdf_sha1": "3fcd0bbbc8ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07332', 'social-worker', 'social-worker-moex-101-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '方案執行結束後要做評估，在評估的類型中有一種是判定方案的執行達到整體方案目標的程度，稱之為：', '["總結評估（summative evaluation）", "結果評估（evaluation of outcome）", "適切性評估（evaluation of adequacy）", "成本效益評估（evaluation of efficiency）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "4f33f4a30a29", "answer_pdf_sha1": "3fcd0bbbc8ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07333', 'social-worker', 'social-worker-moex-101-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社工員的士氣對社會福利組織而言很重要，根據福洛姆（V.Vroom）的期望理論，下列那一項概念可顯示 社工員對自己付出的努力是否可以使工作表現達到水準？', '["吸引力", "績效-酬償的關聯性", "努力-績效的關聯性", "績效的工具性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "4f33f4a30a29", "answer_pdf_sha1": "3fcd0bbbc8ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07334', 'social-worker', 'social-worker-moex-101-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '以我國法律之規定，下列何者不是社會福利機構的財源？', '["租金收入", "募款收入", "販售收入", "發行股票或債券"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "4f33f4a30a29", "answer_pdf_sha1": "3fcd0bbbc8ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07335', 'social-worker', 'social-worker-moex-101-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '主要的管理功能中，對人力與資源做分派主要屬於下列那一個功能？', '["規劃", "組織", "領導", "控制"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "4f33f4a30a29", "answer_pdf_sha1": "3fcd0bbbc8ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07336', 'social-worker', 'social-worker-moex-101-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在決定社會工作人員薪資制度時，管理階層對各種不同的職位決定其相對價值的過程稱之為：', '["工作分析", "工作設計", "工作評價", "工作描述"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "4f33f4a30a29", "answer_pdf_sha1": "3fcd0bbbc8ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07337', 'social-worker', 'social-worker-moex-101-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '現代社會工作管理者在人力方面最大的挑戰之一是「聘用的人力愈來愈有差異性」，這個趨勢稱之為：', '["全球化的考驗", "員工多樣化的考驗", "求職人口群異質性的考驗", "勞動者意願下降的考驗"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "4f33f4a30a29", "answer_pdf_sha1": "3fcd0bbbc8ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07338', 'social-worker', 'social-worker-moex-101-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '關於組織管理中所謂的「制度學派」，下列何種論述錯誤？', '["制度學派強調理性設計比歷史包袱及非預期的效應重要", "制度學派強調公信力與合法性", "制度學派強調組織文化的重要", "制度學派強調環境對於組織的影響"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "4f33f4a30a29", "answer_pdf_sha1": "3fcd0bbbc8ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07339', 'social-worker', 'social-worker-moex-101-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列關於服務品質的描述，何者有誤？', '["ISO9000是服務品質外部認證的一種制度", "社會福利的服務品質通常不易定義，除了案主的感受之外，常與案主所處社會環境的認定有關", "全面品質管理（TQM）由商業型組織發展而來，社會福利組織因其特殊性質，並不適合TQM的引介", "社會福利的服務品質通常包括多元層面，所以需要多層級或多層面的衡量"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "4f33f4a30a29", "answer_pdf_sha1": "3fcd0bbbc8ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
